import{_ as s,o as a,c as i,ai as n}from"./chunks/framework.C4ntERNc.js";const u=JSON.parse('{"title":"Clock Domains","description":"","frontmatter":{"title":"Clock Domains","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/clock-domains.md","filePath":"reference-manual/clock-domains.md"}'),l={name:"reference-manual/clock-domains.md"};function t(o,e,c,r,d,p){return a(),i("div",null,[...e[0]||(e[0]=[n(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/clock-domains.md for this page in Markdown format</div><h1 id="clock-domains" tabindex="-1">Clock Domains <a class="header-anchor" href="#clock-domains" aria-label="Permalink to “Clock Domains”">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h2><p>Clock domains are explicit in JZ-HDL. Registers have a single home domain (the clock they are synchronized to). Direct use of a register across different clock domains is forbidden. The <code>CDC</code> block provides explicit, designer‑declared crossings that create safe, compiler‑understood synchronized views of register values between domains.</p><p>Key goals:</p><ul><li>Make cross‑domain behavior explicit and auditable.</li><li>Prevent accidental multi‑domain register usage.</li><li>Let the compiler enforce domain locality and generate appropriate synchronizer structures.</li></ul><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to “Syntax”">​</a></h2><p>CDC entries appear inside a module body in a <code>CDC { ... }</code> block.</p><p>Basic form:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>CDC {</span></span>
<span class="line"><span>  &lt;cdc_type&gt;[n_stages] &lt;source_reg&gt; (&lt;src_clk&gt;) =&gt; &lt;dest_alias&gt; (&lt;dest_clk&gt;);</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span>}</span></span></code></pre></div><ul><li><code>cdc_type</code> is one of: <code>BIT</code>, <code>BUS</code>, <code>FIFO</code>, <code>HANDSHAKE</code>, <code>PULSE</code>, <code>MCP</code>, <code>RAW</code></li><li><code>[n_stages]</code> optional positive integer; default = 2 (must NOT be provided for <code>RAW</code>)</li><li><code>source_reg</code>: a <code>REGISTER</code> identifier defined in the same module (plain name, no slices/concat)</li><li><code>(src_clk)</code>: clock identifier for the source/home domain (must match a <code>SYNCHRONOUS</code> block <code>CLK</code> or a top-level clock input)</li><li><code>=&gt; dest_alias (dest_clk)</code>: creates a read‑only alias visible in the destination clock domain</li></ul><p>Examples:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>CDC {</span></span>
<span class="line"><span>  BIT    status_sync (clk_io) =&gt; cpu_status (clk_cpu);</span></span>
<span class="line"><span>  BUS[3] flags_bus    (clk_a)  =&gt; flags_view (clk_b);</span></span>
<span class="line"><span>  FIFO[4] payload     (clk_prod) =&gt; consumer_view (clk_cons);</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="semantics" tabindex="-1">Semantics <a class="header-anchor" href="#semantics" aria-label="Permalink to “Semantics”">​</a></h2><ul><li>The CDC entry sets the <strong>home clock domain</strong> of the source register to <code>src_clk</code>.</li><li>The dest alias is a read‑only signal that represents the synchronized view of the source register after approximately <code>n_stages</code> cycles in the destination clock.</li><li>The source register may only be read/written in <code>SYNCHRONOUS</code> blocks whose <code>CLK</code> equals <code>src_clk</code> (its home domain).</li><li>The dest alias may only be read in <code>SYNCHRONOUS</code> blocks whose <code>CLK</code> equals <code>dest_clk</code>. It can also be read combinationally in <code>ASYNCHRONOUS</code> blocks, but that combinational use must respect domain semantics (see &quot;Usage Notes&quot;).</li><li>The compiler elaborates the <code>CDC</code> entry into appropriate synchronization hardware: <ul><li><code>BIT[n]</code>: N-stage single-bit flip-flop synchronizer. The source register <strong>must have width [1]</strong> — using BIT with a multi-bit register is a compile error (<code>CDC_BIT_WIDTH_NOT_1</code>).</li><li><code>BUS[n]</code>: Multi‑bit synchronized path; intended only when the source follows Gray‑code or single‑bit change discipline.</li><li><code>FIFO[n]</code>: Asynchronous FIFO for arbitrary multi‑bit transfers (handles wide or multi‑bit simultaneous changes safely).</li><li><code>HANDSHAKE[n]</code>: Req/ack handshake protocol for infrequent multi‑bit transfers.</li><li><code>PULSE[n]</code>: Toggle-based pulse synchronizer. The source register <strong>must have width [1]</strong> — using PULSE with a multi-bit register is a compile error (<code>CDC_PULSE_WIDTH_NOT_1</code>).</li><li><code>MCP[n]</code>: Multi‑cycle path formulation for stable multi‑bit data.</li><li><code>RAW</code>: Direct unsynchronized wire connection (no crossing logic).</li></ul></li></ul><h2 id="cdc-types-and-intended-use" tabindex="-1">CDC Types and Intended Use <a class="header-anchor" href="#cdc-types-and-intended-use" aria-label="Permalink to “CDC Types and Intended Use”">​</a></h2><ul><li><p>BIT[n_stages]</p><ul><li>Use for single‑bit control/status signals.</li><li>Result <code>dest_alias</code> width: 1.</li><li><code>n_stages</code> typically 2 or 3 in practice.</li><li>Latency: exactly <code>n_stages</code> cycles of <code>dest_clk</code>.</li></ul></li><li><p>BUS[n_stages]</p><ul><li>Use for multi‑bit values that change in a safe, bounded way (e.g., Gray‑encoded counters, handshaked state encodings where only one bit flips at a time).</li><li>Not safe for arbitrary parallel changes (multi‑bit updates).</li><li>If source can change arbitrarily, prefer <code>FIFO</code>.</li><li>Latency: exactly <code>n_stages</code> cycles of <code>dest_clk</code>.</li></ul></li><li><p>FIFO[n_stages]</p><ul><li>Use for arbitrary multi‑bit transfers (data buses, registers updated with new values every cycle).</li><li>Produces a staged, safe transfer; semantics approximates a buffer or asynchronous FIFO depending on implementation.</li><li>Latency: between 1 cycle (existing data) and <code>n_stages + 2</code> cycles (fresh write).</li></ul></li><li><p>HANDSHAKE[n_stages]</p><ul><li>Use for infrequent multi‑bit transfers where throughput is not critical.</li><li>Source latches data and asserts request; destination syncs request, latches data, and asserts ack; source syncs ack and deasserts request.</li><li>Safe for arbitrary data widths.</li><li>Latency: variable depending on clock ratio; transfer completes after full req/ack handshake.</li></ul></li><li><p>PULSE[n_stages]</p><ul><li>Use for single‑bit pulse events (width == 1 only).</li><li>Source toggles a register on each pulse; destination syncs the toggle and XOR‑detects edges to produce output pulses.</li><li>Latency: <code>n_stages</code> cycles for pulse detection; one output pulse per input pulse.</li></ul></li><li><p>MCP[n_stages]</p><ul><li>Multi‑cycle path formulation for stable multi‑bit data transfers.</li><li>Source holds data stable and asserts an enable; destination syncs the enable and samples data when the enable is seen.</li><li>Uses the same req/ack protocol as HANDSHAKE for safe handoff.</li><li>Latency: variable, similar to HANDSHAKE; data held stable during transfer.</li></ul></li><li><p>RAW</p><ul><li>Direct unsynchronized view — no crossing logic is inserted.</li><li>The destination alias is a direct wire connection (<code>assign</code>) to the source register.</li><li>The <code>[n_stages]</code> parameter must NOT be provided (compile error if present).</li><li>Any register width is allowed.</li><li>Latency: 0 cycles (direct connection).</li><li>Use only when the designer knows the signals are safe (e.g., quasi‑static configuration registers, signals with external synchronization, or signals that are stable at the time of sampling).</li><li><strong>Warning:</strong> RAW explicitly opts out of CDC safety guarantees. Metastability protection is the designer&#39;s responsibility.</li></ul></li></ul><h2 id="validation-rules-compiler-enforced" tabindex="-1">Validation Rules (Compiler Enforced) <a class="header-anchor" href="#validation-rules-compiler-enforced" aria-label="Permalink to “Validation Rules (Compiler Enforced)”">​</a></h2><ul><li>Source register must be a <code>REGISTER</code> declared in the containing module.</li><li>Source register identifier must be a plain name (no slices, concatenations, instance-qualified names).</li><li>The <code>CDC</code> entry establishes the home domain for the source register; that register: <ul><li>May only be assigned (in <code>SYNCHRONOUS</code>) inside a <code>SYNCHRONOUS</code> block whose <code>CLK</code> equals <code>src_clk</code>.</li><li>May only be read inside <code>SYNCHRONOUS</code> blocks whose <code>CLK</code> equals <code>src_clk</code>.</li><li>Any attempt to use the source register in a <code>SYNCHRONOUS</code> block with a different <code>CLK</code> is a DOMAIN_CONFLICT error.</li></ul></li><li>The dest alias: <ul><li>Is created by the compiler as a read‑only signal name (not a register the designer assigns).</li><li>May only be read in <code>SYNCHRONOUS</code> blocks whose <code>CLK</code> equals <code>dest_clk</code>.</li><li>Attempting to assign to the dest alias is a compile error.</li></ul></li><li>A module may have at most one <code>SYNCHRONOUS</code> block per unique clock signal. (See SYNCHRONOUS block rules.)</li><li>Multiple CDC entries may declare crossings between the same pair of clocks or different clocks; each source register&#39;s home domain is set by its CORESCDC entry.</li><li>If a register is referenced by a CDC entry, that CDC entry must appear before any <code>SYNCHRONOUS</code> block that uses the alias or the source register (tool-specific ordering rule for resolvability).</li><li>For <code>BUS[n_stages]</code>, compiler may generate warnings if it detects potential multi‑bit simultaneous changes that violate Gray‑code assumptions (static/flow analysis best‑effort).</li></ul><h2 id="usage-notes" tabindex="-1">Usage Notes <a class="header-anchor" href="#usage-notes" aria-label="Permalink to “Usage Notes”">​</a></h2><ul><li>The <code>CDC</code> block does not replace proper CDC design discipline; it documents intent and enables the toolchain to synthesize correct synchronizers and raise violations.</li><li>The destination alias is an explicit name you should use in the destination domain&#39;s synchronous logic, not the source register name. <ul><li>Correct: <code>IF (cpu_status) { ... }</code> where <code>cpu_status</code> is <code>dest_alias</code>.</li><li>Incorrect: reading <code>status_reg</code> inside <code>CLK=cpu_clk</code> when <code>status_reg</code> is home to <code>clk_io</code>.</li></ul></li><li><code>dest_alias</code> is visible combinationally in <code>ASYNCHRONOUS</code> blocks, but be careful: combinational logic that mixes <code>dest_alias</code> with signals from the destination clock domain should not be used to create cross‑domain control paths (avoid asynchronous handshakes without explicit synchronizers).</li><li>If you need to sample a multi‑bit value that changes arbitrarily, use <code>FIFO</code> to avoid metastability and data corruption.</li><li>A single register may have multiple destination aliases to different clocks (fan‑out synchronization to multiple domains).</li></ul><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to “Examples”">​</a></h2><p>Single‑bit synchronizer (2 stages default):</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>REGISTER {</span></span>
<span class="line"><span>  event_flag [1] = 1&#39;b0;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CDC {</span></span>
<span class="line"><span>  BIT event_flag (clk_io) =&gt; event_flag_cpu (clk_cpu);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SYNCHRONOUS(CLK=clk_io) {</span></span>
<span class="line"><span>  // source domain: write-only here</span></span>
<span class="line"><span>  IF (some_condition) {</span></span>
<span class="line"><span>    event_flag = 1&#39;b1;</span></span>
<span class="line"><span>  } ELSE {</span></span>
<span class="line"><span>    event_flag = 1&#39;b0;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SYNCHRONOUS(CLK=clk_cpu) {</span></span>
<span class="line"><span>  // destination domain: read the alias</span></span>
<span class="line"><span>  IF (event_flag_cpu) {</span></span>
<span class="line"><span>    // handle event (synchronized)</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Multi‑bit Gray‑code bus:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>REGISTER {</span></span>
<span class="line"><span>  gray_ptr [8] = 8&#39;h00; // gray-coded pointer in producer domain</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CDC {</span></span>
<span class="line"><span>  BUS[3] gray_ptr (clk_prod) =&gt; gray_ptr_cons (clk_cons);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SYNCHRONOUS(CLK=clk_cons) {</span></span>
<span class="line"><span>  // safe if gray_ptr follows Gray-code discipline</span></span>
<span class="line"><span>  next_read_ptr = gray_ptr_cons;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Wide arbitrary data via FIFO:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>REGISTER {</span></span>
<span class="line"><span>  packet_word [64] = 64&#39;h0000_0000_0000_0000;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CDC {</span></span>
<span class="line"><span>  FIFO[4] packet_word (clk_src) =&gt; packet_view (clk_dst);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SYNCHRONOUS(CLK=clk_dst) {</span></span>
<span class="line"><span>  // consumer reads packet_view; FIFO ensures safe transfer</span></span>
<span class="line"><span>  data_out &lt;= packet_view;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Raw unsynchronized view (quasi‑static config register):</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>REGISTER {</span></span>
<span class="line"><span>  config_word [16] = 16&#39;h0000; // written once at startup, stable thereafter</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CDC {</span></span>
<span class="line"><span>  RAW config_word (clk_cpu) =&gt; config_view (clk_periph);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SYNCHRONOUS(CLK=clk_periph) {</span></span>
<span class="line"><span>  // safe because config_word is quasi-static (written once, then stable)</span></span>
<span class="line"><span>  local_config &lt;= config_view;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="common-errors-and-diagnostics" tabindex="-1">Common Errors and Diagnostics <a class="header-anchor" href="#common-errors-and-diagnostics" aria-label="Permalink to “Common Errors and Diagnostics”">​</a></h2><ul><li><p>DOMAIN_CONFLICT</p><ul><li>Cause: Using a <code>REGISTER</code> in a synchronous block whose <code>CLK</code> differs from the register&#39;s home domain (as set by CDC or by where the register is first assigned).</li><li>Fix: Move the register usage to the correct <code>SYNCHRONOUS</code> block or add a CDC entry that creates an alias for cross‑domain use.</li></ul></li><li><p>DUPLICATE_CDC_ENTRY</p><ul><li>Cause: Two CDC entries attempt to set home domain for the same source register inconsistently.</li><li>Fix: Consolidate CDC entries; each register should have a single definitive home domain.</li></ul></li><li><p>INVALID_CDC_TARGET</p><ul><li>Cause: The source register is not a plain register identifier (slice, concat, or undefined).</li><li>Fix: Use the plain register name; if you need to cross slices or fields, create separate registers or use FIFO.</li></ul></li><li><p>INVALID_CDC_TYPE</p><ul><li>Cause: Using <code>BIT</code> for multi‑bit sources or <code>BUS</code> for sources that change arbitrarily.</li><li>Fix: Use the correct CDC type. Use <code>BIT</code> for width==1, <code>BUS</code> only when Gray‑code discipline is followed, otherwise <code>FIFO</code>.</li></ul></li><li><p>UNSAFE_BUS_WARNING (warning)</p><ul><li>Cause: Static/heuristic analysis detects that a <code>BUS</code> source may change multiple bits simultaneously.</li><li>Fix: Use <code>FIFO</code> or redesign the producer to follow Gray‑code or single‑bit change discipline.</li></ul></li><li><p>MISSING_CDC_FOR_CROSS_DOMAIN_USE</p><ul><li>Cause: A register is referenced in a different domain without a CDC entry.</li><li>Fix: Add a CDC entry or redesign to avoid cross‑domain reads.</li></ul></li><li><p>MULTI_CLK_ASSIGN / REGISTER_LOCALITY_VIOLATION</p><ul><li>Cause: Assigning the same register in more than one <code>SYNCHRONOUS</code> block for different clocks.</li><li>Fix: Ensure a register is written only in its home domain; use CDC to observe it elsewhere.</li></ul></li></ul><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to “Best Practices”">​</a></h2><ul><li><p>Be explicit and conservative:</p><ul><li>Prefer <code>FIFO</code> for multi‑bit transfers unless you can guarantee single‑bit changes (Gray code) and understand the implications.</li><li>Use <code>BIT[2]</code> or <code>BIT[3]</code> for status/control signals; 2 stages is common, 3 for safety in noisy environments.</li></ul></li><li><p>Name aliases clearly:</p><ul><li>Use systematic naming like <code>reg_sync_destclk</code> or <code>src_to_dst_signal</code> so intent is obvious.</li></ul></li><li><p>One synchronous block per clock:</p><ul><li>Place all logic for a given clock in the same <code>SYNCHRONOUS(CLK=...)</code> block to satisfy Synchronous Block Uniqueness.</li></ul></li><li><p>Keep CDC block near register declarations:</p><ul><li>Place <code>CDC { ... }</code> entries close to the <code>REGISTER</code> declarations for readability and to help tools resolve names.</li></ul></li><li><p>Document constraints:</p><ul><li>If a <code>BUS</code> CDC requires Gray‑coding, document the producer&#39;s requirement in comments and add static checks or assertions when possible.</li></ul></li><li><p>Verify with static checks and timing:</p><ul><li>Run CDC-specific static checks and, where possible, formal checks to ensure no combinational paths create control hazards across domains.</li><li>Ensure timing constraints for synchronizers are included in downstream SDC (synthesis/timing) flows.</li></ul></li></ul><h2 id="anti‐patterns-what-to-avoid" tabindex="-1">Anti‑patterns (What to avoid) <a class="header-anchor" href="#anti‐patterns-what-to-avoid" aria-label="Permalink to “Anti‑patterns (What to avoid)”">​</a></h2><ul><li>Reading a source register directly in another clock domain without CDC — causes DOMAIN_CONFLICT and metastability.</li><li>Using <code>BUS</code> for wide registers that can change every cycle with arbitrary bit patterns — leads to data corruption.</li><li>Mixing alias names and source register names across domains (ambiguous intent).</li><li>Trying to synchronize slices of a multi‑bit register via separate <code>BIT</code> synchronizers without ensuring atomic update semantics on the producer side.</li></ul><h2 id="checklist-for-adding-a-cdc-crossing" tabindex="-1">Checklist for Adding a CDC Crossing <a class="header-anchor" href="#checklist-for-adding-a-cdc-crossing" aria-label="Permalink to “Checklist for Adding a CDC Crossing”">​</a></h2><ul><li>Confirm the source is a <code>REGISTER</code> and has a single, clear producer domain.</li><li>Decide the appropriate CDC type: <ul><li>BIT → single‑bit flag.</li><li>BUS → multi‑bit Gray‑code or single‑bit change guaranteed.</li><li>FIFO → arbitrary multi‑bit transfers.</li><li>RAW → quasi‑static or externally synchronized signals (no CDC logic inserted).</li></ul></li><li>Choose <code>n_stages</code> (default 2). For safety or noisy inputs, increase to 3.</li><li>Add the <code>CDC</code> entry near the register declaration.</li><li>Replace any cross‑domain uses with reads of the <code>dest_alias</code>.</li><li>Run static checks; address compiler warnings/errors.</li><li>Add documentation/comments explaining invariants (e.g., Gray‑code property).</li></ul><h2 id="synthesis-and-implementation-notes" tabindex="-1">Synthesis and Implementation Notes <a class="header-anchor" href="#synthesis-and-implementation-notes" aria-label="Permalink to “Synthesis and Implementation Notes”">​</a></h2><ul><li>The compiler will lower <code>CDC</code> entries into synthesizable primitives: <ul><li>BIT → chain of flip‑flops with optional meta‑stable handling.</li><li>BUS → bank of flip‑flops and optional handshaking or gating depending on implementation.</li><li>FIFO → dual‑clock FIFO or asynchronous FIFO implementation using pointers and synchronizers.</li></ul></li><li>Downstream tools should map these to: <ul><li>Vendor synchronizer primitives or hand‑optimized flops.</li><li>FIFO IP blocks for <code>FIFO</code> CDC entries when available.</li></ul></li><li>Ensure timing constraints (SDC) include created synchronizer registers so STA correctly analyzes setup/hold for destination domain.</li></ul>`,40)])])}const g=s(l,[["render",t]]);export{u as __pageData,g as default};
